SELECT b.brand_name, d.distribution_name
FROM brands b
LEFT JOIN distribution_metrics d ON b.brand_id = d.distribution_id;

SELECT channel_type, MAX(commission_rate) AS highest_commission_rate, MIN(commission_rate) AS lowest_commission_rate
FROM channels
GROUP BY channel_type;

SELECT owner_name, contact_info
FROM owners
WHERE owner_id = 0;

SELECT channel_name, channel_type
FROM channels
WHERE channel_id = 1;

SELECT COUNT(DISTINCT sku) AS unique_product_count
FROM products
WHERE price_tier = 'Budget';

SELECT channel_name
FROM channels
WHERE commission_rate > 0.10;

SELECT *
FROM products
WHERE pack_size = (SELECT MIN(pack_size) FROM products);

SELECT channel_name 
FROM channels 
WHERE channel_id > 5000;
